  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Connect to database and ensure table exists
    auto db = sqlgen::sqlite::connect("test_db.sqlite")
                  .and_then(create_table<Book> | if_not_exists);

    // Read all books from database
    auto all_books = db.and_then(read<std::vector<Book>>);

    if (!all_books) {
        return std::vector<Book>();
    }

    // Filter results based on provided criteria
    std::vector<Book> results;

    for (const auto& book : all_books.value()) {
        bool matches = true;

        // Filter by title keyword (LIKE operation)
        if (filters.title_keyword.has_value()) {
            if (book.title.find(*filters.title_keyword) == std::string::npos) {
                matches = false;
            }
        }

        // Filter by minimum year (>= operation)
        if (matches && filters.min_year.has_value()) {
            if (book.year < *filters.min_year) {
                matches = false;
            }
        }

        // Filter by genre (= operation)
        if (matches && filters.genre.has_value()) {
            if (book.genre != *filters.genre) {
                matches = false;
            }
        }

        // Filter by maximum price (<= operation)
        if (matches && filters.max_price.has_value()) {
            if (book.price > *filters.max_price) {
                matches = false;
            }
        }

        if (matches) {
            results.push_back(book);
        }
    }

    return results;
}

}  // namespace query_search_books_by_criteria
