Looking at the requirements and the code fragments provided, I need to:

1. Connect to SQLite database "test_db.sqlite"
2. Start a transaction
3. Check if the sender has sufficient funds
4. Deduct from sender account
5. Add to receiver account
6. Commit if successful, rollback if any step fails
7. Return true if successful, false otherwise

From the code fragments, I can see that:
- `sqlgen::sqlite::connect()` is used to connect to a database
- The library uses a monadic style with `.and_then()` for chaining operations
- There's a pattern of using `using namespace sqlgen;` and `using namespace sqlgen::literals;`

For SQLite transactions, I need to:
1. Connect to the database with the specific file name
2. Begin a transaction
3. Perform the updates
4. Commit or rollback

Looking at the API patterns, I would expect something like:
- `sqlgen::sqlite::connect("test_db.sqlite")` to connect to a specific database
- Some way to execute transactions
- Update operations

Since I need to:
1. Check balance >= amount for from_account
2. Update from_account: balance = balance - amount WHERE account_id = from_account_id AND balance >= amount
3. Update to_account: balance = balance + amount WHERE account_id = to_account_id

The function should return bool indicating success or failure.

Let me write the implementation:

```cpp
bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  try {
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");

    // Begin transaction
    conn = conn.and_then(execute("BEGIN TRANSACTION"));

    // Check balance and update sender account
    // UPDATE Account SET balance = balance - ? WHERE account_id = ? AND balance >= ?
    auto result = conn.and_then(
      update<Account>()
        .set("balance"_c = "balance"_c - amount)
        .where("account_id"_c == from_account_id && "balance"_c >= amount)
    );

    // If no rows affected, insufficient funds
    if (!result || result.rows_affected() == 0) {
      conn.and_then(execute("ROLLBACK"));
      return false;
    }

    // Update receiver account and add funds
    result = result.and_then(
      update<Account>()
        .set("balance"_c = "balance"_c + amount)
        .where("account_id"_c == to_account_id)
    );

    // Commit transaction if both updates succeeded
    if (result && result.rows_affected() > 0) {
      conn.and_then(execute("COMMIT"));
      return true;
    } else {
      conn.and_then(execute("ROLLBACK"));
      return false;
    }
  } catch (...) {
    return false;
