bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) return false;

  auto conn = *conn_result;

  try {
    // Begin transaction
    auto begin = conn.execute("BEGIN TRANSACTION");
    if (!begin) return false;

    // Deduct from sender account (only if sufficient balance exists)
    auto deduct = conn.execute(
      "UPDATE Account SET balance = balance - ? WHERE account_id = ? AND balance >= ?",
      amount, from_account_id, amount
    );

    // Check if any row was updated (account exists and has sufficient funds)
    if (!deduct || deduct->rows_affected() == 0) {
      conn.execute("ROLLBACK");
      return false;
    }

    // Add to receiver account
    auto add = conn.execute(
      "UPDATE Account SET balance = balance + ? WHERE account_id = ?",
      amount, to_account_id
    );

    // Check if receiver account was updated
    if (!add || add->rows_affected() == 0) {
      conn.execute("ROLLBACK");
      return false;
    }

    // Commit transaction
    auto commit = conn.execute("COMMIT");
    if (!commit) {
      conn.execute("ROLLBACK");
      return false;
    }

    return true;

  } catch (...) {
    // Attempt rollback on any exception
    try {
      conn.execute("ROLLBACK");
    } catch (...) {
      // Ignore rollback errors
    }
    return false;
  }
}

}  // namespace transaction_transfer_funds
```

