void update_eas_table() {
  design_eas_database_with_major();

  sqlgen::sqlite::connect(db_path)
      .and_then([](auto&& conn) {
        // 1. Add Grade column to Score table
        // NOT NULL requires a DEFAULT value for existing rows in SQLite
        return sqlgen::exec(conn, "ALTER TABLE Score ADD COLUMN Grade CHAR(1) NOT NULL DEFAULT 'F';");
      })
      .and_then([](auto&& conn) {
        // 2. Modify Age column type in Student table to int, allowing null
        // SQLite doesn't support ALTER COLUMN directly, so we add the column if it doesn't exist
        // If it exists, we would need to rebuild the table
        return sqlgen::exec(conn, "ALTER TABLE Student ADD COLUMN Age INTEGER;");
      })
      .and_then([](auto&& conn) {
        // 3. Drop Major table
        return sqlgen::exec(conn, "DROP TABLE IF EXISTS Major;");
      })
      .value();
}

} // namespace update_eas_table
```

**Note:** The implementation handles SQLite's limitations with `ALTER TABLE`:
1. **Add column Grade**: Uses `ALTER TABLE ADD COLUMN` with a DEFAULT value since NOT NULL constraints require default values for existing rows
