  sqlgen::PrimaryKey<int> user_id;
  std::optional<std::string> bio;
  std::optional<std::string> avatar_url;
};

bool upsert_user_profile(const UserProfile& u) {
  using namespace sqlgen;

  // SQLite supports INSERT OR REPLACE directly
  // Connect to the database and perform upsert operation
  auto result = sqlite::connect("test_db.sqlite")
                    .and_then(insert_or_replace(u));

  // Return true if operation succeeded, false otherwise
  return result.has_value();
}

} // namespace upsert_user_profile
```

**Explanation:**

1. **Database Connection**: Uses `sqlite::connect("test_db.sqlite")` to connect to the SQLite database file.

2. **Upsert Operation**: Uses `insert_or_replace(u)` which translates to SQLite's `INSERT OR REPLACE` statement. This will:
   - Insert a new record if the `user_id` doesn't exist
   - Replace (update) the existing record if the `user_id` already exists

3. **Monadic Pattern**: Follows the library's pattern using `and_then()` to chain operations.

4. **Return Value**: Returns `true` if the operation succeeded, `false` if it failed (checked via `has_value()`).

**Note**: If `insert_or_replace` is not available in your version of `sqlgen`, you can alternatively use:

```cpp
// Alternative approach using raw SQL (if supported)
