#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace schema_create_view_sales_summary {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
  int stock;
};

struct Sale {
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct SalesSummary {
  static constexpr bool is_view = true;
  std::string product_name;
  int total_quantity;
  double total_revenue;
};

/**
 * Function: Create a view SalesSummary that aggregates sales by product.
 * 
 * @return true if view creation succeeds, false otherwise
 */
bool create_view_sales_summary() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Drop the view if it exists to ensure clean creation
  const std::string drop_view_sql = "DROP VIEW IF EXISTS SalesSummary";

  // Create the view with aggregation by product
  const std::string create_view_sql = R"(
CREATE VIEW SalesSummary AS
SELECT p.name as product_name, 
       SUM(s.quantity) as total_quantity, 
       SUM(s.amount) as total_revenue
FROM Sale s
JOIN Product p ON s.product_id = p.product_id
GROUP BY p.name
)";

  // Connect to database and execute the commands
  auto result = sqlgen::sqlite::connect("test_db.sqlite")
    .and_then(sqlgen::execute(drop_view_sql))
    .and_then(sqlgen::execute(create_view_sql));

  return result.has_value();
}

}  // namespace schema_create_view_sales_summary
```

This implementation:

1. **Defines the View struct**: The `SalesSummary` struct is already defined with `is_view = true` to indicate it's a view, not a table.

2. **Constructs the SELECT query**: The SQL query performs a JOIN between `Sale` and `Product` tables on `product_id`, aggregates using `SUM()` for quantity and amount, and groups by product name.

3. **Handles DROP IF EXISTS**: Since SQLite might not support `CREATE VIEW IF NOT EXISTS` in all versions, the function uses `DROP VIEW IF EXISTS` followed by `CREATE VIEW` to ensure the view is created cleanly.

4. **Executes the commands**: Uses sqlgen's functional pipeline with `connect()` → `and_then(execute())` to execute the SQL commands.

