#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace right_join_departments_projects {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string name;
};

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  int department_id;
  std::string name;
};

struct DepProj {
  std::optional<std::string> department_name;
  std::string project_name;
};

/**
 * description: right_join_departments_projects.
 * This function demonstrates how to perform a right join between departments and projects using sqlgen read API.
 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 */
std::vector<DepProj> right_join_departments_projects() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // SQLite doesn't support RIGHT JOIN directly, so we simulate it with LEFT JOIN
  // To include all departments (even those without projects), we perform:
  // Department LEFT JOIN Project, which gives us all departments
  // 
  // However, based on the DepProj struct (project_name is required, department_name is optional),
  // this appears to actually want all projects with optional departments
  // This would be: Project LEFT JOIN Department ON Project.department_id = Department.department_id

  auto result = sqlite::connect("test_db.sqlite")
    .and_then([](auto conn) {
      return conn.template read<std::vector<DepProj>>(
        "SELECT d.name as department_name, p.name as project_name "
        "FROM Project p "
        "LEFT JOIN Department d ON p.department_id = d.department_id"
      );
    });

  return result.value_or(std::vector<DepProj>{});
}

}  // namespace right_join_departments_projects
```

**Note:** The implementation assumes that despite the requirement stating "include all departments", the `DepProj` struct definition (with `project_name` as non-optional and `department_name` as optional) indicates we actually want all projects with their associated departments (where department may be null). 

If the true intent is to get all departments with their projects (departments without projects would have null project names), the struct definition should be modified to make `project_name` optional instead of `department_name`.

