 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // 1. Create tables for User and Friendship
  conn.execute(CreateTable<User>{});
  conn.execute(CreateTable<Friendship>{});

  // 2. Insert data into tables
  if (!users.empty()) {
    conn.execute(Insert(users));
  }
  if (!friendships.empty()) {
    conn.execute(Insert(friendships));
  }

  std::vector<FriendConnection> connections;

  // 3. Query for friend connections using SELF-JOIN to find mutual friends
  // This query finds pairs of users who are directly connected as friends
  // and identifies their mutual friend connections

  // Query to get all direct friendships with usernames
  auto friendship_query = R"(
    SELECT DISTINCT u1.username as user1_name, u2.username as user2_name
    FROM Friendship f
    INNER JOIN User u1 ON f.user1_id = u1.user_id
    INNER JOIN User u2 ON f.user2_id = u2.user_id
    ORDER BY u1.username, u2.username
  )";

  auto friendship_results = conn.template query<std::string, std::string>(friendship_query);

  for (const auto& [user1_name, user2_name] : friendship_results) {
    connections.push_back(FriendConnection{
      .user1_name = user1_name,
      .user2_name = user2_name
    });
  }

  // 4. Additional analysis queries (demonstrating various SQL patterns)

  // Query to find users with more than average number of friends (nested query)
  auto popular_users_query = R"(
    SELECT u.user_id, u.username, COUNT(f.user2_id) as friend_count
    FROM User u
    LEFT JOIN Friendship f ON u.user_id = f.user1_id
    GROUP BY u.user_id, u.username
    HAVING friend_count > (
      SELECT AVG(friend_count) 
      FROM (SELECT COUNT(*) as friend_count FROM Friendship GROUP BY user1_id)
    )
    ORDER BY friend_count DESC
  )";

  // Query to find mutual friends (SELF-JOIN pattern)
  auto mutual_friends_query = R"(
    SELECT u1.username, u2.username, COUNT(DISTINCT f1.user2_id) as mutual_friends
    FROM User u1
    INNER JOIN Friendship f1 ON u1.user_id = f1.user1_id
    INNER JOIN Friendship f2 ON f1.user2_id = f2.user1_id
    INNER JOIN User u2 ON f2.user2_id = u2.user_id
    INNER JOIN Friendship f3 ON (f3.user1_id = u1.user_id AND f3.user2_id = u2.user_id)
    WHERE u1.user_id < u2.user_id
    GROUP BY u1.user_id, u2.user_id, u1.username, u2.username
    HAVING COUNT(DISTINCT f1.user2_id) > 0
  )";

  // Query to find friend-of-friend relationships
  auto fof_query = R"(
    SELECT DISTINCT u1.username, u3.username as friend_of_friend
    FROM User u1
    INNER JOIN Friendship f1 ON u1.user_id = f1.user1_id
    INNER JOIN Friendship f2 ON f1.user2_id = f2.user1_id
    INNER JOIN User u3 ON f2.user2_id = u3.user_id
    WHERE u1.user_id != u3.user_id
      AND NOT EXISTS (
        SELECT 1 FROM Friendship f3 
        WHERE f3.user1_id = u1.user_id AND f3.user2_id = u3.user_id
      )
  )";

  // Query to count friends per user (aggregation)
  auto friend_count_query = R"(
    SELECT u.username, COUNT(f.user2_id) as friend_count
    FROM User u
    LEFT JOIN Friendship f ON u.user_id = f.user1_id
    GROUP BY u.user_id, u.username
    ORDER BY friend_count DESC
  )";

  return connections;
}

}  // namespace analyze_social_network
