```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Enable foreign key constraints (required for SQLite)
  conn.exec("PRAGMA foreign_keys = ON");

  // Drop tables if they exist (for clean slate)
  conn.exec("DROP TABLE IF EXISTS Child");
  conn.exec("DROP TABLE IF EXISTS Parent");

  // Create Parent table
  conn.exec(R"(
    CREATE TABLE Parent (
      parent_id INTEGER PRIMARY KEY,
      name VARCHAR NOT NULL
    )
  )");

  // Create Child table with CASCADE DELETE constraint
  conn.exec(R"(
    CREATE TABLE Child (
      child_id INTEGER PRIMARY KEY,
      parent_id INTEGER,
      note VARCHAR,
      FOREIGN KEY (parent_id) REFERENCES Parent(parent_id) ON DELETE CASCADE
    )
  )");

  // Insert parent record
  conn.exec("INSERT INTO Parent (parent_id, name) VALUES (1, 'Test Parent')");

  // Insert child records with the same parent_id
  conn.exec("INSERT INTO Child (child_id, parent_id, note) VALUES (1, 1, 'Child 1')");
  conn.exec("INSERT INTO Child (child_id, parent_id, note) VALUES (2, 1, 'Child 2')");

  // Verify children exist before deletion
  auto result_before = conn.query("SELECT COUNT(*) FROM Child WHERE parent_id = 1");
  int count_before = 0;
  if (result_before.next()) {
    count_before = result_before.get<int>(0);
  }

  // Delete parent record
  conn.exec("DELETE FROM Parent WHERE parent_id = 1");

  // Verify children are automatically deleted due to CASCADE
  auto result_after = conn.query("SELECT COUNT(*) FROM Child WHERE parent_id = 1");
  int count_after = 0;
  if (result_after.next()) {
    count_after = result_after.get<int>(0);
  }

  // Return true if cascade delete worked correctly
  // (2 children before deletion, 0 children after)
  return (count_before == 2 && count_after == 0);
}

}  // namespace cascade_delete_demo
