# Complete File

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // SQLite doesn't support FULL OUTER JOIN natively, so we simulate it
  // using UNION of LEFT JOIN and the complementary set
  const std::string full_join_query = R"(
    SELECT s.name as supplier_name, p.name as product_name
    FROM Supplier s
    LEFT JOIN Product p ON s.supplier_id = p.supplier_id
    UNION
    SELECT COALESCE(s.name, 'Unknown') as supplier_name, p.name as product_name
    FROM Product p
    LEFT JOIN Supplier s ON p.supplier_id = s.supplier_id
    WHERE s.supplier_id IS NULL
  )";

  // Connect to the SQLite database and execute the query
  auto result = sqlgen::sqlite::connect("test_db.sqlite")
    .and_then(sqlgen::raw<std::vector<SupProd>>(full_join_query));

  // Return the result or an empty vector if there was an error
  if (result) {
    return result.value();
  }
  return std::vector<SupProd>{};
}

}  // namespace full_join_suppliers_products
```

**Key Implementation Details:**

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to connect to the specified database file.

2. **FULL JOIN Simulation**: Since SQLite doesn't natively support FULL OUTER JOIN, the implementation simulates it using:
   - LEFT JOIN from Supplier to Product (gets all suppliers with their products)
   - UNION with LEFT JOIN from Product to Supplier WHERE supplier is NULL (gets products without suppliers)
   - Uses `COALESCE(s.name, 'Unknown')` to handle NULL supplier names for products without suppliers

3. **Result Mapping**: The query projects to match the `SupProd` struct with `supplier_name` (non-optional) and `product_name` (optional).

4. **Error Handling**: Returns an empty vector if the database operation fails.

