```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace delete_with_complex_condition {

struct User {
  sqlgen::PrimaryKey<int> id;
  int age;
  std::string status;
};

/**
 * This function demonstrates deleting with complex conditions.
 * Returns: std::string.
 */
inline std::string delete_with_complex_condition() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Construct a DELETE query with complex OR condition
    // Delete users where age < 18 OR status = 'inactive'
    auto query = remove<User>()
        .where("age"_c < 18 || "status"_c == "inactive");

    // Return the generated SQL string
    return query.sql();
}

}  // namespace delete_with_complex_condition
```

## Explanation:

1. **Using directives**: Import `sqlgen` namespace and `literals` for column literal syntax (`"column_name"_c`).

2. **DELETE query construction**: Use `remove<User>()` to create a DELETE query for the User table.

3. **Complex condition**: Use the `.where()` method with an OR condition:
   - `"age"_c < 18` - users younger than 18
   - `||` - logical OR operator
   - `"status"_c == "inactive"` - users with inactive status

4. **SQL generation**: Call `.sql()` on the query object to generate and return the SQL string.

The generated SQL should be something like:
```sql
DELETE FROM User WHERE age < 18 OR status = 'inactive'
```

