#include <gtest/gtest.h>
#include "update_inventory_stock.hpp"

namespace update_inventory_stock {

TEST(sqlite, update_inventory_stock) {
  using namespace sqlgen;
  auto conn = sqlite::connect("test_db.sqlite").value();
  drop<Product>(conn);
  create_table<Product>(conn);

  insert(conn, std::vector<Product>{{1, 10}, {2, 5}, {3, 0}});

  std::unordered_map<int, int> shipment{{1, 5}, {2, 10}, {3, 2}};
  ASSERT_TRUE(update_inventory_stock(shipment));

  auto rows = sqlgen::read<std::vector<Product>>(conn).value();
  auto find = [&](int id) {
    return std::find_if(rows.begin(), rows.end(),
                        [&](const Product& p) { return p.product_id.value() == id; });
  };
  EXPECT_EQ(find(1)->stock, 15);
  EXPECT_EQ(find(2)->stock, 15);
  EXPECT_EQ(find(3)->stock, 2);
}

}  // namespace update_inventory_stock

