```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace create_view_order_summary {

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  std::string customer;
};

struct OrderItem {
  sqlgen::PrimaryKey<int> item_id;
  int order_id;
  double unit_price;
  int quantity;
};

struct OrderSummary {
  static constexpr const char* tablename = "OrderSummaryView";
  static constexpr bool is_view = true;
  sqlgen::PrimaryKey<int> order_id;
  std::string customer;
  double total;
};

/**
 * Description: This function demonstrates creating a view.
 * Returns: std::vector<OrderSummary>.
 */
std::vector<OrderSummary> create_view_order_summary() {
    using namespace sqlgen;

    // Connect to SQLite database
    auto db = sqlgen::sqlite::Database("test_db.sqlite");

    // Create the view with aggregated totals per order
    // This creates: CREATE VIEW OrderSummaryView AS
    // SELECT o.order_id, o.customer, SUM(oi.unit_price*oi.quantity) as total
    // FROM Order o INNER JOIN OrderItem oi ON o.order_id=oi.order_id
    // GROUP BY o.order_id, o.customer
    db.create_view_as<OrderSummary>(
        "OrderSummaryView",
        db.select_from<Order>()
          .inner_join<OrderItem>(&Order::order_id == &OrderItem::order_id)
          .select(&Order::order_id, &Order::customer, 
                  sum(&OrderItem::unit_price * &OrderItem::quantity))
          .group_by(&Order::order_id, &Order::customer)
    );

    // Read from the view to verify data
    auto results = db.select_from<OrderSummary>().run();

    return results;
}

}  // namespace create_view_order_summary
```

