```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  // Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // SQL query to extract weekday and aggregate quantities
  // In SQLite, strftime('%w', datetime) returns day of week (0-6, where 0=Sunday)
  // Group by weekday and sum the quantities
  const std::string query = R"(
    SELECT CAST(strftime('%w', sale_time) AS INTEGER) as weekday,
           SUM(quantity) as total_quantity
    FROM Sales
    GROUP BY strftime('%w', sale_time)
    ORDER BY weekday
  )";

  // Execute the query and map results to WeekdayStats
  auto results = conn.query<WeekdayStats>(query);

  return results;
}

}  // namespace weekday_sales_analysis
```

This implementation:

1. **Connects to the database**: Uses `sqlgen::sqlite::connect()` to open a connection to "test_db.sqlite"

2. **Extracts weekday**: Uses SQLite's `strftime('%w', sale_time)` function which returns the day of week as a number (0-6, where 0 is Sunday)

3. **Aggregates totals**: Uses `SUM(quantity)` grouped by the weekday to calculate total quantities sold per day

4. **Returns structured data**: Maps the query results to `WeekdayStats` structs containing weekday number and total quantity, ordered by weekday for consistent results

The query produces one row per weekday (0-6) with the total quantity sold on that day of the week across all sales records.

