# Complete Implementation

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace group_by_with_aggregations {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  std::string content;
};

struct Stats {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  int post_count;
  std::optional<double> avg_length;
};

/**
 * Description: This function retrieves user statistics including post count and average post length.
 * Returns: std::vector<Stats>.
 */
std::vector<Stats> group_by_with_aggregations() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto db = sqlite::Database("test_db.sqlite");

  // Get table references
  auto user_table = db.table<User>("User");
  auto post_table = db.table<Post>("Post");

  // Perform join, group by, and aggregations
  // Join User and Post on user_id, group by user, compute COUNT and AVG(length(content))
  auto results = user_table
    .left_join(post_table, user_table.user_id == post_table.user_id)
    .group_by(user_table.user_id, user_table.name)
    .select<Stats>(
      user_table.user_id,
      user_table.name,
      count(post_table.post_id),
      avg(length(post_table.content))
    )
    .all();

  return results;
}

}  // namespace group_by_with_aggregations
```

This implementation:
1. **Connects to the database**: Opens "test_db.sqlite" using `sqlite::Database`
2. **Gets table references**: Creates references to User and Post tables
3. **Performs LEFT JOIN**: Joins User and Post tables on `user_id` field
4. **Groups by user**: Groups results by `user_id` and `name`
5. **Computes aggregations**: 
   - `COUNT(post_id)` for post count
   - `AVG(length(content))` for average content length
6. **Returns results**: Maps to `Stats` structure and returns as a vector

The use of `left_join` ensures all users are included even if they have no posts, and `std::optional<double>` for `avg_length` handles cases where users have no posts (NULL average).

